function calculate({ portfolioValue, geopoliticalExposurePercentage, conflictIntensityScore, marketVolatilityImpact, politicalStabilityIndex, economicInterdependenceFactor, hedgingStrategyEffectiveness }) {

    // Input validation and normalization
    portfolioValue = Math.max(0, parseFloat(portfolioValue) || 0);
    geopoliticalExposurePercentage = Math.max(0, Math.min(100, parseFloat(geopoliticalExposurePercentage) || 0));
    conflictIntensityScore = Math.max(1, Math.min(10, parseFloat(conflictIntensityScore) || 1));
    marketVolatilityImpact = Math.max(0, Math.min(1, parseFloat(marketVolatilityImpact) || 0));
    politicalStabilityIndex = Math.max(1, Math.min(10, parseFloat(politicalStabilityIndex) || 1));
    economicInterdependenceFactor = Math.max(1, Math.min(10, parseFloat(economicInterdependenceFactor) || 1));
    hedgingStrategyEffectiveness = Math.max(0, Math.min(100, parseFloat(hedgingStrategyEffectiveness) || 0));

    if (portfolioValue === 0) {
        return {
            geopoliticalRiskIndex: 0,
            potentialPortfolioLoss: 0,
            riskCategory: 'No Portfolio Value'
        };
    }

    // Step 1: Calculate initial exposure-based risk
    const exposedPortfolioValue = portfolioValue * (geopoliticalExposurePercentage / 100);

    // Step 2: Adjust for conflict intensity and market volatility
    // Conflict intensity multiplier: higher score = higher multiplier
    const conflictMultiplier = 1 + (conflictIntensityScore - 1) * 0.15; // Ranges from 1 (score 1) to 2.35 (score 10)

    // Market volatility multiplier: direct impact
    const volatilityMultiplier = 1 + marketVolatilityImpact; // Ranges from 1 (0) to 2 (1.0)

    let adjustedRisk = exposedPortfolioValue * conflictMultiplier * volatilityMultiplier;

    // Step 3: Adjust for political stability and economic interdependence
    // Political stability multiplier: lower stability = higher multiplier
    const stabilityMultiplier = 1 + (10 - politicalStabilityIndex) * 0.08; // Ranges from 1 (stable 10) to 1.72 (unstable 1)

    // Economic interdependence multiplier: higher interdependence = higher multiplier (more spread risk)
    const interdependenceMultiplier = 1 + (economicInterdependenceFactor - 1) * 0.05; // Ranges from 1 (isolated 1) to 1.45 (interdependent 10)

    adjustedRisk = adjustedRisk * stabilityMultiplier * interdependenceMultiplier;

    // Step 4: Apply hedging effectiveness
    const effectiveHedging = 1 - (hedgingStrategyEffectiveness / 100);
    let potentialPortfolioLoss = adjustedRisk * effectiveHedging;

    // Cap potential loss at 100% of the exposed portfolio value or 50% of total portfolio value, whichever is lower.
    // This prevents unrealistically high losses beyond a certain point relative to total assets.
    const maxPossibleLoss = Math.min(exposedPortfolioValue, portfolioValue * 0.50);
    potentialPortfolioLoss = Math.min(potentialPortfolioLoss, maxPossibleLoss);

    // Step 5: Calculate Geopolitical Investment Risk Index (normalized 0-100)
    // The index is a percentage of the calculated potential loss relative to the total portfolio value.
    let geopoliticalRiskIndex = (potentialPortfolioLoss / portfolioValue) * 100;

    // Cap the index at 100, minimum at 0
    geopoliticalRiskIndex = Math.max(0, Math.min(100, geopoliticalRiskIndex));

    // Determine risk category
    let riskCategory;
    if (geopoliticalRiskIndex < 10) {
        riskCategory = 'Very Low Risk';
    } else if (geopoliticalRiskIndex < 25) {
        riskCategory = 'Low Risk';
    } else if (geopoliticalRiskIndex < 50) {
        riskCategory = 'Moderate Risk';
    } else if (geopoliticalRiskIndex < 75) {
        riskCategory = 'High Risk';
    } else {
        riskCategory = 'Severe Risk';
    }

    return {
        geopoliticalRiskIndex: geopoliticalRiskIndex,
        potentialPortfolioLoss: potentialPortfolioLoss,
        riskCategory: riskCategory
    };
}
